features.snippet:
parameter ss = 5;
localparam w = 1 << ss;
reg [w-1:0] acc2;
wire [w/2-1:0] bbit = 1 << bitl;
wire [w-1:0] bit2 = 1 << (bitl << 1);

always @(posedge clk or posedge reset)
  if (reset) begin
    acc = 0;
    acc2 = 0;
    bitl = w / 2 - 1;
  end
  else begin
    if (guess2 <= x) begin
      acc <= guess;
      acc2 <= guess2;
    end
    bitl <= bitl - 1;
  end
